static APP_NAMES: [&str; APP_NUM] = [
    "00_hello",
    "01_busy",
    "02_raw",
    "03_fork_wait",
    "04_getpid_sleep",
];

static APPS: [&[u8]; APP_NUM] = [
    APP_00_HELLO,
    APP_01_BUSY,
    APP_02_RAW,
    APP_03_FORK_WAIT,
    APP_04_GETPID_SLEEP,
];

pub fn get_app_data(app_id: usize) -> &'static [u8] {
    APPS.get(app_id).copied().unwrap_or_else(|| panic!("bad app id {}", app_id))
}

pub fn get_app_name(app_id: usize) -> &'static str {
    APP_NAMES.get(app_id).copied().unwrap_or_else(|| panic!("bad app id {}", app_id))
}
